INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Break the ice', 'Przełamać lody — rozpocząć rozmowę w niezręcznej sytuacji. Np. ''His joke helped break the ice at the meeting.''', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hit the nail on the head', 'Trafić w sedno — powiedzieć dokładnie to, co trzeba. Np. ''You hit the nail on the head with that analysis.''', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A piece of cake', 'Bułka z masłem — coś bardzo łatwego. Np. ''The exam was a piece of cake.''', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bite the bullet', 'Zacisnąć zęby — zrobić coś nieprzyjemnego, co jest nieuniknione. Np. ''I bit the bullet and went to the dentist.''', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cost an arm and a leg', 'Kosztować majątek — być bardzo drogim. Np. ''That designer bag cost an arm and a leg.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Let the cat out of the bag', 'Wygadać się — zdradzić sekret. Np. ''She let the cat out of the bag about the surprise party.''', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Once in a blue moon', 'Raz na ruski rok — bardzo rzadko. Np. ''He only visits once in a blue moon.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Burn the midnight oil', 'Siedzieć nad czymś do późna — pracować do późnych godzin nocnych. Np. ''She burned the midnight oil to finish the report.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The ball is in your court', 'Twój ruch — teraz od ciebie zależy decyzja. Np. ''I''ve made my offer — the ball is in your court.''', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spill the beans', 'Wygadać się — ujawnić tajemnicę. Np. ''Come on, spill the beans! What happened?''', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kill two birds with one stone', 'Upiec dwie pieczenie na jednym ogniu — osiągnąć dwa cele jednym działaniem. Np. ''By cycling to work, I kill two birds with one stone — I save money and exercise.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Under the weather', 'Kiepsko się czuć — być chorym lub nie w formie. Np. ''I''m feeling a bit under the weather today.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sit on the fence', 'Być niezdecydowanym — nie zajmować stanowiska. Np. ''Stop sitting on the fence and make a decision.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Beat around the bush', 'Owijać w bawełnę — nie mówić wprost. Np. ''Stop beating around the bush and tell me the truth.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Get cold feet', 'Dostać zimnych nóg — stchórzyć w ostatniej chwili. Np. ''He got cold feet before the wedding.''', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A blessing in disguise', 'Szczęście w nieszczęściu — coś pozornie złego, co okazuje się dobre. Np. ''Losing that job was a blessing in disguise.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Barking up the wrong tree', 'Mylić się co do przyczyny — szukać w złym miejscu. Np. ''If you think I did it, you''re barking up the wrong tree.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Actions speak louder than words', 'Czyny mówią głośniej niż słowa — to co robisz jest ważniejsze od tego, co mówisz. Np. ''Don''t just promise — actions speak louder than words.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Add insult to injury', 'Dosypać soli do rany — pogorszyć i tak złą sytuację. Np. ''To add insult to injury, it started raining when my car broke down.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cut to the chase', 'Przejść do rzeczy — pominąć zbędne wstępy. Np. ''Let''s cut to the chase — how much will it cost?''', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Every cloud has a silver lining', 'Nie ma tego złego, co by na dobre nie wyszło. Np. ''I know you''re upset, but every cloud has a silver lining.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Go the extra mile', 'Dać z siebie więcej niż wymagane — wykazać się ponadprzeciętnym zaangażowaniem. Np. ''She always goes the extra mile for her clients.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('It takes two to tango', 'Do tanga trzeba dwojga — obie strony są odpowiedzialne. Np. ''Don''t blame just him — it takes two to tango.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Miss the boat', 'Przegapić okazję — spóźnić się z czymś. Np. ''If you don''t apply today, you''ll miss the boat.''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('On thin ice', 'Stąpać po cienkim lodzie — być w ryzykownej sytuacji. Np. ''After arriving late again, he''s on thin ice with the boss.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pull someone''s leg', 'Nabierać kogoś — żartować z kogoś. Np. ''Are you serious or just pulling my leg?''', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The best of both worlds', 'Połączyć przyjemne z pożytecznym — mieć zalety dwóch opcji naraz. Np. ''Working from home gives me the best of both worlds.''', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('When pigs fly', 'Jak rak świśnie — nigdy. Np. ''He''ll clean his room when pigs fly.''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Steal someone''s thunder', 'Ukraść komuś show — przypisać sobie czyjś sukces. Np. ''She stole my thunder by announcing my idea first.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The last straw', 'Ostatnia kropla przepełniająca czarę — ostateczny powód wybuchu. Np. ''His rudeness was the last straw — I quit.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Throw in the towel', 'Rzucić ręcznik — poddać się. Np. ''After months of trying, she threw in the towel.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A penny for your thoughts', 'O czym myślisz? — pytanie o czyjeś przemyślenia. Np. ''You look worried — a penny for your thoughts?''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Better late than never', 'Lepiej późno niż wcale. Np. ''You finally started exercising — better late than never!''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Call it a day', 'Zakończyć pracę na dziś — skończyć na dany dzień. Np. ''We''ve done enough — let''s call it a day.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Don''t cry over spilt milk', 'Nie płacz nad rozlanym mlekiem — nie rozpaczaj nad tym, czego nie da się cofnąć. Np. ''The vase is broken — don''t cry over spilt milk.''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Easier said than done', 'Łatwiej powiedzieć niż zrobić. Np. ''Quitting smoking is easier said than done.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Get out of hand', 'Wymknąć się spod kontroli. Np. ''The party got out of hand when more people arrived.''', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hang in there', 'Trzymaj się — nie poddawaj się. Np. ''I know it''s tough, but hang in there.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('In the same boat', 'W tej samej sytuacji — dzielić ten sam problem. Np. ''We''re all in the same boat with these budget cuts.''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Jump on the bandwagon', 'Przyłączyć się do popularnego trendu. Np. ''Everyone jumped on the bandwagon when the stock started rising.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Keep your chin up', 'Głowa do góry — nie trać ducha. Np. ''Keep your chin up — things will get better.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leave no stone unturned', 'Nie zostawić kamienia na kamieniu — sprawdzić wszystkie możliwości. Np. ''The police left no stone unturned in their search.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Make a long story short', 'Krótko mówiąc — streścić długą historię. Np. ''To make a long story short, we missed the flight.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('No pain, no gain', 'Bez pracy nie ma kołaczy — trzeba się postarać, żeby coś osiągnąć. Np. ''Keep training — no pain, no gain.''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Off the top of my head', 'Z głowy — bez przygotowania, spontanicznie. Np. ''Off the top of my head, I''d say there were about 50 people.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Put all your eggs in one basket', 'Stawiać wszystko na jedną kartę. Np. ''Don''t put all your eggs in one basket — diversify your investments.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Read between the lines', 'Czytać między wierszami — rozumieć ukryty sens. Np. ''If you read between the lines, she''s not happy with the plan.''', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('See eye to eye', 'Zgadzać się — mieć to samo zdanie. Np. ''We don''t always see eye to eye, but we respect each other.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Take it with a grain of salt', 'Brać z przymrużeniem oka — nie traktować dosłownie. Np. ''He exaggerates — take what he says with a grain of salt.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Under someone''s nose', 'Pod czyimś nosem — tuż obok, niepostrzeżenie. Np. ''The answer was right under my nose the whole time.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wrap your head around something', 'Ogarnąć coś — zrozumieć coś skomplikowanego. Np. ''I can''t wrap my head around quantum physics.''', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('You can''t judge a book by its cover', 'Nie oceniaj książki po okładce — pozory mylą. Np. ''He looks tough, but he''s kind — you can''t judge a book by its cover.''', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bite off more than you can chew', 'Porwać się z motyką na słońce — podjąć się zbyt dużego zadania. Np. ''I think she bit off more than she can chew with this project.''', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cross that bridge when you come to it', 'Nie wyprzedzać faktów — zająć się problemem, gdy się pojawi. Np. ''Don''t worry now — we''ll cross that bridge when we come to it.''', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Don''t put the cart before the horse', 'Nie stawiaj wozu przed koniem — nie rób rzeczy w złej kolejności. Np. ''Let''s plan first — don''t put the cart before the horse.''', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Give someone the benefit of the doubt', 'Dać komuś kredyt zaufania. Np. ''I''ll give him the benefit of the doubt and assume it was an accident.''', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hit the road', 'Ruszać w drogę — wyruszać. Np. ''It''s getting late — let''s hit the road.''', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('On the same page', 'Być zgodnym — mieć wspólne rozumienie sytuacji. Np. ''Let''s make sure we''re on the same page before the meeting.''', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('The tip of the iceberg', 'Wierzchołek góry lodowej — mała widoczna część dużego problemu. Np. ''The complaints we''ve received are just the tip of the iceberg.''', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Up in the air', 'Sprawa nierozstrzygnięta — jeszcze niezadecydowane. Np. ''Our vacation plans are still up in the air.''', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('agenda', 'Porządek obrad — lista tematów do omówienia na spotkaniu. Np. ''Let''s go through the agenda.''', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to schedule a meeting', 'Zaplanować spotkanie. Np. ''Can we schedule a meeting for next Tuesday?''', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('deadline', 'Termin ostateczny — nieprzekraczalna data wykonania zadania. Np. ''The deadline for the report is Friday.''', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to negotiate', 'Negocjować — prowadzić rozmowy w celu osiągnięcia porozumienia. Np. ''We need to negotiate better terms.''', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('revenue', 'Przychód — łączna kwota pieniędzy zarobionych przez firmę. Np. ''Revenue increased by 15% this quarter.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('profit margin', 'Marża zysku — procent przychodu, który zostaje jako zysk. Np. ''Our profit margin has improved significantly.''', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('stakeholder', 'Interesariusz — osoba lub grupa mająca wpływ na projekt lub zainteresowana jego wynikiem. Np. ''We need to inform all stakeholders.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to delegate tasks', 'Delegować zadania — przydzielać obowiązki innym. Np. ''A good manager knows how to delegate tasks effectively.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('KPI (Key Performance Indicator)', 'Kluczowy wskaźnik efektywności — miara oceny sukcesu. Np. ''Our main KPI is customer satisfaction rate.''', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to brainstorm', 'Burza mózgów — wspólne generowanie pomysłów. Np. ''Let''s brainstorm ideas for the new campaign.''', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('bottom line', 'Wynik końcowy / sedno sprawy — najważniejszy rezultat finansowy. Np. ''The bottom line is we need to cut costs.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to follow up', 'Kontynuować / dopytać — wrócić do sprawy. Np. ''I''ll follow up with you next week on this matter.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('quarterly report', 'Raport kwartalny — sprawozdanie z wyników za kwartał. Np. ''The quarterly report shows strong growth.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to outsource', 'Zlecać na zewnątrz — przekazywać zadania firmie zewnętrznej. Np. ''We decided to outsource our IT support.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ROI (Return on Investment)', 'Zwrot z inwestycji — miara opłacalności inwestycji. Np. ''What''s the expected ROI on this project?''', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to pitch an idea', 'Przedstawić pomysł — zaprezentować koncepcję w celu jej sprzedania. Np. ''She pitched the idea to the board of directors.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('target audience', 'Grupa docelowa — odbiorcy, do których kierowany jest produkt lub komunikat. Np. ''Our target audience is millennials.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to close a deal', 'Sfinalizować transakcję — doprowadzić negocjacje do końca. Np. ''We managed to close the deal yesterday.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('cash flow', 'Przepływ pieniężny — ruch środków finansowych w firmie. Np. ''We need to improve our cash flow.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to scale up', 'Skalować — zwiększać rozmiar operacji lub działalności. Np. ''We plan to scale up production next year.''', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('benchmark', 'Punkt odniesienia — standard, z którym porównuje się wyniki. Np. ''We use industry benchmarks to evaluate our performance.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to streamline', 'Usprawnić — uprościć proces, aby był bardziej efektywny. Np. ''We need to streamline our approval process.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('leverage', 'Dźwignia / wykorzystać — użyć czegoś w celu uzyskania przewagi. Np. ''We can leverage our brand to enter new markets.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to onboard', 'Wdrożyć — wprowadzić nowego pracownika lub klienta. Np. ''We onboarded three new employees this month.''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('synergy', 'Synergia — współdziałanie dające lepszy efekt niż suma części. Np. ''The merger created strong synergies between teams.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Please find attached', 'W załączeniu przesyłam — formalna fraza w e-mailach. Np. ''Please find attached the report for Q3.''', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('As per our conversation', 'Zgodnie z naszą rozmową — nawiązanie do wcześniejszych ustaleń. Np. ''As per our conversation, I''m sending the updated proposal.''', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('I look forward to hearing from you', 'Z niecierpliwością czekam na odpowiedź — formalne zakończenie e-maila. Np. ''I look forward to hearing from you at your earliest convenience.''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to touch base', 'Skontaktować się krótko — sprawdzić aktualny stan sprawy. Np. ''Let''s touch base on Friday to review progress.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to get the ball rolling', 'Ruszyć z miejsca — rozpocząć działanie. Np. ''Let''s get the ball rolling on this project.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('competitive advantage', 'Przewaga konkurencyjna — cecha wyróżniająca firmę na tle konkurencji. Np. ''Our technology gives us a competitive advantage.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to break even', 'Wyjść na zero — osiągnąć punkt, w którym przychody równają się kosztom. Np. ''We expect to break even by the end of the year.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to downsize', 'Redukować zatrudnienie — zmniejszać liczbę pracowników. Np. ''The company had to downsize due to the recession.''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('supply chain', 'Łańcuch dostaw — system produkcji i dystrybucji produktu. Np. ''The pandemic disrupted global supply chains.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('overhead costs', 'Koszty stałe / ogólne — wydatki niezwiązane bezpośrednio z produkcją (czynsz, media). Np. ''We need to reduce our overhead costs.''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to implement', 'Wdrożyć — wprowadzić w życie plan lub system. Np. ''We''re implementing a new CRM system.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('due diligence', 'Należyta staranność — dogłębna analiza przed decyzją biznesową. Np. ''We conducted due diligence before the acquisition.''', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to diversify', 'Dywersyfikować — różnicować, poszerzać zakres działalności. Np. ''We need to diversify our product portfolio.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('merger', 'Fuzja — połączenie dwóch firm w jedną. Np. ''The merger created the largest company in the sector.''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('acquisition', 'Przejęcie — zakup jednej firmy przez drugą. Np. ''The acquisition was worth $2 billion.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to allocate resources', 'Przydzielić zasoby — rozdzielić budżet, czas lub ludzi do zadań. Np. ''We need to allocate more resources to R&D.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('turnaround', 'Zwrot / naprawa — proces odwracania negatywnych tendencji w firmie. Np. ''The new CEO led an impressive turnaround.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to liaise with', 'Utrzymywać kontakt / współpracować — pełnić rolę łącznika. Np. ''I liaise with the marketing team on campaign strategy.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ballpark figure', 'Przybliżona kwota — szacunkowa liczba. Np. ''Can you give me a ballpark figure for the project cost?''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('action items', 'Punkty do realizacji — zadania do wykonania po spotkaniu. Np. ''Let me summarize the action items from today''s meeting.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to circle back', 'Wrócić do tematu — ponownie omówić sprawę. Np. ''Let''s circle back on this topic next week.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pain point', 'Problem / bolączka — trudność, z którą boryka się klient. Np. ''We identified the main pain points of our users.''', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to sign off on', 'Zatwierdzić — dać formalną zgodę. Np. ''The manager needs to sign off on the budget.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('win-win situation', 'Sytuacja korzystna dla obu stron. Np. ''This partnership is a win-win situation for both companies.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to phase out', 'Wycofywać stopniowo — eliminować etapami. Np. ''We''re phasing out the old software over the next six months.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('feasibility study', 'Studium wykonalności — analiza, czy projekt jest możliwy do realizacji. Np. ''We need a feasibility study before committing funds.''', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to mitigate risks', 'Łagodzić ryzyko — zmniejszać prawdopodobieństwo lub skutki zagrożeń. Np. ''We have a plan to mitigate the main risks.''', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to meet a target', 'Osiągnąć cel — zrealizować założony plan. Np. ''The sales team met their quarterly target.''', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to go live', 'Uruchomić — wdrożyć system do użytku. Np. ''The new website will go live on Monday.''', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('scope creep', 'Pełzanie zakresu — niekontrolowane rozszerzanie się projektu. Np. ''We must avoid scope creep to stay on budget.''', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to ramp up', 'Zwiększać intensywność — przyspieszać. Np. ''We''re ramping up production to meet demand.''', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pro rata', 'Proporcjonalnie — w stosunku do udziału lub czasu. Np. ''Your bonus will be calculated pro rata.''', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to table a discussion', 'Odłożyć dyskusję na później (AmE) / Przedstawić do dyskusji (BrE). Np. ''Let''s table this and revisit it next meeting.''', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('workflow', 'Przepływ pracy — sekwencja kroków w procesie. Np. ''We redesigned our workflow to improve efficiency.''', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('to wrap up', 'Podsumować / zakończyć — zamknąć spotkanie lub temat. Np. ''Let''s wrap up — any final questions?''', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Present Simple — kiedy używamy?', 'Czynności rutynowe, fakty, prawdy ogólne, rozkłady jazdy. Np. ''I work every day.'' ''Water boils at 100°C.'' Przysłówki: always, usually, often, sometimes, never.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Continuous — kiedy używamy?', 'Czynności odbywające się w momencie mówienia, tymczasowe, zaplanowane w bliskiej przyszłości. Np. ''I''m working now.'' ''She''s leaving tomorrow.'' Budowa: am/is/are + V-ing.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Simple — kiedy używamy?', 'Czynności zakończone w przeszłości w określonym czasie. Np. ''I visited Paris last year.'' Określniki: yesterday, last week, in 2020, ago.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Continuous — kiedy używamy?', 'Czynności trwające w określonym momencie w przeszłości lub przerwane przez inną czynność. Np. ''I was reading when the phone rang.'' Budowa: was/were + V-ing.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect — kiedy używamy?', 'Czynności z przeszłości mające związek z teraźniejszością, doświadczenia życiowe, czynności niezakończone. Np. ''I have visited Paris three times.'' ''She has lived here since 2010.''', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect Continuous — kiedy?', 'Czynności rozpoczęte w przeszłości i trwające do teraz, podkreślenie czasu trwania. Np. ''I have been waiting for two hours.'' Budowa: have/has been + V-ing.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Past Perfect — kiedy używamy?', 'Czynność zakończona przed inną czynnością w przeszłości. Np. ''I had already eaten when she arrived.'' Budowa: had + past participle (V3).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Future Simple (will) vs Going to', '''Will'' — spontaniczne decyzje, przewidywania, obietnice. ''Going to'' — plany, zamiary, wyraźne oznaki. Np. ''I''ll help you.'' vs ''I''m going to study medicine.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używamy ''a'' a kiedy ''an''?', '''a'' przed spółgłoską (dźwięk): a car, a university (ju-). ''an'' przed samogłoską (dźwięk): an apple, an hour (ałer). Decyduje dźwięk, nie litera.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kiedy używamy ''the''?', 'Gdy mówimy o czymś konkretnym, znanym rozmówcom, jedynym w swoim rodzaju. Np. ''the sun'', ''the book I told you about''. Nie używamy z nazwami krajów (wyjątki: the UK, the USA), językami, posiłkami.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Countable vs Uncountable nouns', 'Policzalne: a chair, two books — mają liczbę mnogą. Niepoliczalne: water, information, advice, furniture — nie mają l.mn., nie używamy ''a/an''. Używamy: much/little (niepoliczalne), many/few (policzalne).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Some vs Any', '''Some'' — zdania twierdzące i uprzejme prośby: ''I have some money.'' ''Would you like some tea?'' ''Any'' — pytania i przeczenia: ''Do you have any questions?'' ''I don''t have any time.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Much / Many / A lot of', '''Much'' + niepoliczalne (pytania, przeczenia): ''How much water?'' ''Many'' + policzalne: ''How many books?'' ''A lot of'' — uniwersalne, zdania twierdzące: ''I have a lot of friends.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (Passive Voice) — budowa', 'Podmiot + be (w odpowiednim czasie) + past participle (V3). Np. Active: ''They build houses.'' Passive: ''Houses are built.'' Past: ''The letter was sent yesterday.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Reported Speech — zasady', 'Cofamy czas o jeden stopień: Present → Past, Past → Past Perfect, will → would. Np. ''I am happy'' → He said he was happy. ''I will come'' → She said she would come.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('First Conditional', 'Realna sytuacja w przyszłości. Budowa: If + Present Simple, will + bezokolicznik. Np. ''If it rains, I will stay at home.'' Nie używamy ''will'' po ''if''.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Second Conditional', 'Nierealna/hipotetyczna sytuacja teraźniejsza. Budowa: If + Past Simple, would + bezokolicznik. Np. ''If I had more money, I would travel the world.'' ''If I were you, I would accept.''', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Third Conditional', 'Nierealna sytuacja w przeszłości (żal, wyobrażenie). Budowa: If + Past Perfect, would have + V3. Np. ''If I had studied harder, I would have passed the exam.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Relative clauses — who, which, that', '''who'' — ludzie: ''The man who called you.'' ''which'' — rzeczy: ''The book which I read.'' ''that'' — ludzie i rzeczy (nieformalnie). W defining clauses ''that'' może zastąpić ''who/which''.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gerund vs Infinitive', 'Gerund (-ing) po: enjoy, avoid, finish, mind, suggest. Infinitive (to) po: want, decide, hope, promise, agree. Niektóre zmieniają znaczenie: ''stop smoking'' vs ''stop to smoke''.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Since vs For (czas trwania)', '''Since'' + punkt w czasie: since 2010, since Monday. ''For'' + okres: for 3 years, for 2 hours. Używane z Present Perfect: ''I have lived here since 2010 / for 14 years.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Used to / Would — przeszłe nawyki', '''Used to'' — dawne nawyki i stany: ''I used to play football.'' ''Would'' — tylko powtarzające się czynności (nie stany): ''We would visit grandma every Sunday.'' Nie: ''I would be shy.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Modal verbs — must vs have to', '''Must'' — wewnętrzna konieczność, przekonanie: ''I must study harder.'' ''Have to'' — zewnętrzny przymus: ''I have to wear a uniform.'' Przeczenie: ''mustn''t'' = zakaz, ''don''t have to'' = brak konieczności.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Should / Ought to', 'Rada, zalecenie, oczekiwanie. Np. ''You should see a doctor.'' ''He ought to apologize.'' ''Ought to'' jest bardziej formalny. Przeczenie: ''shouldn''t'', ''ought not to''.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('May vs Might', 'Oba wyrażają możliwość. ''May'' — większe prawdopodobieństwo: ''It may rain today.'' (50/50). ''Might'' — mniejsze prawdopodobieństwo: ''I might come to the party.'' ''May'' też = pozwolenie formalne: ''May I come in?''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Comparative and Superlative adjectives', 'Krótkie (1 syl.): tall → taller → the tallest. Długie (2+ syl.): interesting → more interesting → the most interesting. Nieregularne: good → better → the best, bad → worse → the worst.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prepositions of time: in, on, at', '''At'' — godziny, momenty: at 5 PM, at night, at Christmas. ''On'' — dni, daty: on Monday, on 1st May. ''In'' — miesiące, lata, pory dnia: in June, in 2024, in the morning.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Prepositions of place: in, on, at', '''In'' — wewnątrz: in the room, in London. ''On'' — na powierzchni: on the table, on the wall. ''At'' — punkt: at the bus stop, at home, at school.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Question tags', 'Zdanie twierdzące → przeczący tag i odwrotnie. Np. ''You are Polish, aren''t you?'' ''She doesn''t like coffee, does she?'' ''They went home, didn''t they?''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('So vs Such', '''So'' + przymiotnik/przysłówek: ''It''s so cold.'' ''Such'' + (a/an) + przymiotnik + rzeczownik: ''It''s such a beautiful day.'' ''She has such nice friends.'' (l.mn. bez ''a'').', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Too vs Enough', '''Too'' + przymiotnik (za bardzo): ''It''s too expensive.'' Przymiotnik + ''enough'' (wystarczająco): ''She''s old enough to drive.'' ''Enough'' + rzeczownik: ''I don''t have enough time.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Still / Yet / Already', '''Still'' — ciągle (zdania twierdzące, pytania): ''I''m still waiting.'' ''Yet'' — jeszcze nie (przeczenia, pytania): ''I haven''t finished yet.'' ''Already'' — już (twierdzenia): ''I''ve already eaten.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Although / Despite / In spite of', '''Although'' + zdanie: ''Although it was cold, we went out.'' ''Despite / In spite of'' + rzeczownik/-ing: ''Despite the rain, we went out.'' ''In spite of being tired, she worked.''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Make vs Do', '''Make'' — tworzenie, wywoływanie: make a decision, make a mistake, make money, make progress. ''Do'' — czynności ogólne, obowiązki: do homework, do the dishes, do business, do a favour.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Say vs Tell', '''Say'' — mówić (coś): ''He said he was tired.'' Nie wymaga dopełnienia osobowego. ''Tell'' — powiedzieć (komuś): ''He told me he was tired.'' Wymaga dopełnienia: tell someone something.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wish + Past Simple / Past Perfect', '''I wish'' + Past Simple — życzenie dotyczące teraźniejszości: ''I wish I had a car.'' ''I wish'' + Past Perfect — żal z powodu przeszłości: ''I wish I had studied harder.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Have something done (causative)', 'Zlecenie usługi — ktoś robi coś za nas. Budowa: have + object + past participle. Np. ''I had my hair cut.'' ''She''s having her car repaired.'' Nie: ''I cut my hair'' (= sama się obcięła).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Neither...nor / Either...or', '''Either...or'' — jeden lub drugi: ''Either you come or you stay.'' ''Neither...nor'' — ani jeden, ani drugi: ''Neither Tom nor Anna was there.'' Czasownik zgodny z bliższym podmiotem.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phrasal verbs — co to jest?', 'Czasownik + przyimek/przysłówek zmieniający znaczenie. Np. ''give up'' = poddać się, ''look after'' = opiekować się, ''put off'' = odłożyć na później, ''turn down'' = odrzucić.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Direct vs Indirect questions', 'Direct: ''Where is the station?'' Indirect (grzeczne): ''Could you tell me where the station is?'' W indirect: szyk oznajmujący (nie inwersja), bez ''do/does/did''.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Adverbs of frequency — szyk zdania', 'Przysłówki częstotliwości (always, usually, often, sometimes, rarely, never) stoją PRZED czasownikiem głównym: ''I always wake up early.'' ALE PO ''be'': ''She is always late.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stative verbs — czym się różnią?', 'Czasowniki stanu nie występują w formach ciągłych (-ing): know, believe, want, need, love, hate, own, seem, belong. Nie: ''I am knowing.'' Tak: ''I know.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('As vs Like', '''Like'' + rzeczownik/zaimek (porównanie): ''She looks like her mother.'' ''As'' + zdanie / funkcja: ''As I said earlier...'' ''He works as a teacher.'' (= jest nauczycielem). Nie: ''He works like a teacher.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Both...and / Not only...but also', '''Both...and'' — oba: ''Both Tom and Anna speak French.'' ''Not only...but also'' — nie tylko, ale także: ''She not only sings but also plays guitar.''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Present Perfect vs Past Simple', 'Past Simple — określony czas: ''I went to London in 2022.'' Present Perfect — brak określonego czasu / związek z teraźniejszością: ''I have been to London.'' ''I''ve just finished.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Unless = If not', '''Unless'' = jeśli nie. Np. ''Unless you hurry, you''ll miss the bus.'' = ''If you don''t hurry, you''ll miss the bus.'' Po ''unless'' nie używamy przeczenia (podwójne przeczenie!).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Each vs Every', '''Each'' — każdy z osobna (mała grupa): ''Each student received a certificate.'' ''Every'' — każdy (ogólnie, duża grupa): ''Every student must pass the exam.'' ''Each'' może stać samodzielnie: ''each of them''.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Will vs Going to — przewidywania', '''Will'' — przewidywanie oparte na opinii: ''I think it will rain.'' ''Going to'' — przewidywanie oparte na dowodach: ''Look at those clouds — it''s going to rain.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zero Conditional', 'Fakty, prawdy ogólne, prawa natury. Budowa: If + Present Simple, Present Simple. Np. ''If you heat water to 100°C, it boils.'' ''If I drink coffee at night, I can''t sleep.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mixed Conditional', 'Łączy II i III conditional. Przeszły warunek → teraźniejszy skutek: ''If I had studied medicine (III), I would be a doctor now (II).'' Teraźniejszy warunek → przeszły skutek: ''If I were braver (II), I would have spoken up (III).''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Ile przypadków jest w języku niemieckim?', 'Cztery: Nominativ (mianownik — kto?), Akkusativ (biernik — kogo/co?), Dativ (celownik — komu?), Genitiv (dopełniacz — czyj?). Np. Der Mann (Nom.) gibt dem Kind (Dat.) den Ball (Akk.).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — odmiana (Nominativ)', 'der (r.m.), die (r.ż.), das (r.n.), die (l.mn.). Np. der Hund, die Katze, das Haus, die Kinder.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Akkusativ', 'den (r.m.), die (r.ż.), das (r.n.), die (l.mn.). Zmienia się TYLKO rodzaj męski: der → den. Np. Ich sehe den Mann. Ich sehe die Frau. Ich sehe das Kind.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Dativ', 'dem (r.m.), der (r.ż.), dem (r.n.), den + -n (l.mn.). Np. Ich gebe dem Mann das Buch. Ich helfe der Frau. Mit den Kindern.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajniki określone — Genitiv', 'des (r.m. + -s/-es), der (r.ż.), des (r.n. + -s/-es), der (l.mn.). Np. das Auto des Mannes, die Tasche der Frau, das Spielzeug des Kindes.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szyk zdania w zdaniu głównym (Hauptsatz)', 'Czasownik odmieniony ZAWSZE na 2. pozycji. Np. ''Ich gehe heute ins Kino.'' ''Heute gehe ich ins Kino.'' (podmiot przesuwa się za czasownik — inwersja).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Szyk zdania w zdaniu pobocznym (Nebensatz)', 'Czasownik odmieniony na KOŃCU zdania. Spójniki: weil, dass, wenn, obwohl, als, ob. Np. ''Ich weiß, dass er morgen kommt.'' ''Weil ich müde bin, gehe ich schlafen.''', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki modalne — lista', 'können (móc/umieć), müssen (musieć), dürfen (mieć pozwolenie), sollen (powinien — polecenie), wollen (chcieć), mögen/möchten (lubić/chciałbym). Czasownik główny na końcu: ''Ich kann schwimmen.''', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Perfekt — budowa', 'haben/sein + Partizip II (na końcu). Np. ''Ich habe gegessen.'' ''Er ist gefahren.'' Sein używamy z czasownikami ruchu (gehen, fahren, kommen) i zmiany stanu (werden, sterben).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Partizip II — jak tworzymy?', 'Regularne: ge- + rdzeń + -t: machen → gemacht, spielen → gespielt. Nieregularne: ge- + rdzeń (zmieniony) + -en: fahren → gefahren, sehen → gesehen. Bez ge-: czasowniki na be-, ver-, er-, ent-: besuchen → besucht.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Präteritum — kiedy używamy?', 'Czas przeszły prosty — głównie w piśmie (literatura, prasa) i z sein/haben. Mówiony niemiecki preferuje Perfekt. Np. ''Ich war müde.'' ''Er hatte keine Zeit.'' ''Sie ging nach Hause.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Akkusativ', 'durch (przez), für (dla), gegen (przeciw), ohne (bez), um (wokół/o). Np. ''Ich arbeite für die Firma.'' ''Er geht durch den Park.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Dativ', 'aus (z), bei (u/przy), mit (z), nach (po/do), seit (od), von (od/z), zu (do). Np. ''Ich komme aus Polen.'' ''Er wohnt bei seinen Eltern.'' ''Seit einem Jahr.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wechselpräpositionen — przyimki zmienne', 'in, an, auf, über, unter, vor, hinter, neben, zwischen — Akkusativ (ruch/kierunek: wohin?) lub Dativ (miejsce/pozycja: wo?). Np. ''Ich gehe in den Park'' (Akk.) vs ''Ich bin im Park'' (Dat.).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki rozdzielnie złożone (trennbare Verben)', 'Przedrostek odłącza się i idzie na koniec: anfangen → ''Ich fange um 8 Uhr an.'' aufstehen → ''Er steht früh auf.'' W Perfekt: ge- między przedrostkiem a rdzeniem: angefangen, aufgestanden.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odmiana przymiotnika po rodzajniku określonym', 'Nominativ: -e (r.m., r.ż., l.mn.), -e (r.n.). Akkusativ: -en (r.m.), -e (r.ż., r.n.). Dativ: zawsze -en. Np. der große Mann, die große Frau, dem großen Kind.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Odmiana przymiotnika po rodzajniku nieokreślonym', 'Nominativ: -er (r.m.), -e (r.ż.), -es (r.n.). Akkusativ: -en (r.m.), -e (r.ż.), -es (r.n.). Np. ein großer Mann, eine große Frau, ein großes Haus.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Konjunktiv II — kiedy i jak?', 'Tryb warunkowy — życzenia, nierealne warunki, grzeczne prośby. Budowa: würde + Infinitiv (większość) lub forma specjalna (hätte, wäre, könnte). Np. ''Ich würde gern reisen.'' ''Wenn ich reich wäre...''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (Passiv) — budowa', 'werden + Partizip II. Np. ''Das Haus wird gebaut.'' (dom jest budowany). Perfekt: ''Das Haus ist gebaut worden.'' Passiv z ''von'' (przez kogo): ''Das Buch wird von dem Autor geschrieben.''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki zwrotne (Reflexivpronomen)', 'Akkusativ: mich, dich, sich, uns, euch, sich. Dativ: mir, dir, sich, uns, euch, sich. Np. ''Ich wasche mich.'' (myję się — Akk.) ''Ich wasche mir die Hände.'' (myję sobie ręce — Dat.)', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Negation: nicht vs kein', '''kein'' neguje rzeczowniki z rodzajnikiem nieokreślonym/bez rodzajnika: ''Ich habe kein Auto.'' ''nicht'' neguje czasowniki, przymiotniki, przysłówki: ''Ich komme nicht.'' ''Es ist nicht groß.''', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zdania względne (Relativsätze)', 'Zaimek względny = rodzajnik określony w odpowiednim przypadku + czasownik na końcu. Np. ''Der Mann, der dort steht, ist mein Lehrer.'' ''Das Buch, das ich lese, ist interessant.''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur I — budowa', 'werden + Infinitiv. Np. ''Ich werde morgen kommen.'' Często w praktyce używa się Present + przysłówek czasu: ''Ich komme morgen.'' Futur I używany też do wyrażania przypuszczeń: ''Er wird wohl krank sein.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'Komparativ: + -er (schnell → schneller). Superlativ: am + -sten (am schnellsten) / der/die/das + -ste. Nieregularne: gut → besser → am besten, viel → mehr → am meisten, gern → lieber → am liebsten.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kolejność: TeKaMoLo', 'W zdaniu niemieckim dopełnienia i okoliczniki w kolejności: Temporal (kiedy?) – Kausal (dlaczego?) – Modal (jak?) – Lokal (gdzie?). Np. ''Ich fahre morgen wegen der Arbeit schnell nach Berlin.''', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spójniki współrzędne (und, aber, oder, denn, sondern)', 'Nie zmieniają szyku zdania (czasownik na 2. pozycji). Np. ''Ich bin müde, aber ich arbeite weiter.'' ''Er kommt nicht, denn er ist krank.'' ''sondern'' — lecz (po przeczeniu): ''nicht A, sondern B''.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Spójniki podrzędne (weil, dass, wenn, obwohl, als, ob)', 'Czasownik odmieniony na końcu zdania pobocznego. Np. ''Ich bleibe zu Hause, weil ich krank bin.'' ''Er fragt, ob du kommst.'' ''als'' = kiedy (jednorazowo w przeszłości), ''wenn'' = kiedy/jeśli (powtarzalnie/przyszłość).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('als vs wenn vs wann', '''als'' — jednorazowe wydarzenie w przeszłości: ''Als ich klein war...'' ''wenn'' — powtarzalne/przyszłe: ''Wenn ich nach Hause komme...'' ''wann'' — pytanie o czas: ''Wann kommst du?''', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki z przyimkiem (Verben mit Präpositionen)', 'Wiele czasowników wymaga określonego przyimka + przypadku. Np. warten auf + Akk. (czekać na), sich freuen auf + Akk. (cieszyć się na), sich freuen über + Akk. (cieszyć się z), denken an + Akk. (myśleć o).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki wymagające Dativ', 'helfen (pomagać), gefallen (podobać się), gehören (należeć do), danken (dziękować), folgen (podążać), antworten (odpowiadać), gratulieren (gratulować). Np. ''Ich helfe dir.'' ''Das Buch gefällt mir.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Podwójny Infinitiv (Doppelter Infinitiv)', 'Z czasownikami modalnymi w Perfekt: ''Ich habe kommen können.'' (Mogłem przyjść) — nie ''gekonnt''. Modalny na końcu, haben jako pomocniczy. Np. ''Er hat nicht arbeiten müssen.''', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativ — tryb rozkazujący', 'du: rdzeń (+ -e opcjonalnie): Komm! Geh! Schreib(e)! ihr: rdzeń + -t: Kommt! Geht! Sie (formal): Infinitiv + Sie: Kommen Sie! Gehen Sie! Np. ''Mach die Tür zu!''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki pytające — przypadki', 'Nominativ: wer (kto), was (co). Akkusativ: wen (kogo), was. Dativ: wem (komu). Genitiv: wessen (czyj). Np. ''Wem gehört das Buch?'' ''Wen hast du gesehen?''', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('es gibt + Akkusativ', '''Es gibt'' = jest/są (istnieje). Zawsze z Akkusativ. Np. ''Es gibt einen Park in der Nähe.'' ''Gibt es hier ein Restaurant?'' Nie mylić z ''es ist'' (opis stanu): ''Es ist kalt.''', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Partizip I jako przymiotnik', 'Infinitiv + -d = Partizip I. Używany jako przymiotnik (odmienialny). Np. schlafend (śpiący): ''das schlafende Kind'', lächelnd (uśmiechający się): ''die lächelnde Frau''.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Plusquamperfekt — budowa', 'hatte/war + Partizip II. Czynność wcześniejsza od innej w przeszłości. Np. ''Nachdem ich gegessen hatte, ging ich spazieren.'' (Po tym jak zjadłem, poszedłem na spacer).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rzeczowniki złożone (Komposita)', 'Niemiecki łączy rzeczowniki w jedno słowo. Ostatni wyraz określa rodzaj i znaczenie główne. Np. der Kühlschrank (die Kühl- + der Schrank = lodówka), das Schlafzimmer (der Schlaf + das Zimmer = sypialnia).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki nieokreślone: man, jemand, niemand', '''man'' — bezosobowe ''się/ktoś'': ''Man spricht hier Deutsch.'' ''jemand'' — ktoś: ''Jemand hat angerufen.'' ''niemand'' — nikt: ''Niemand weiß das.''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Konjunktiv I — mowa zależna (formal)', 'Rdzeń + końcówki: -e, -est, -e, -en, -et, -en. Używany w prasie/oficjalnie. Np. ''Er sagte, er habe keine Zeit.'' (Powiedział, że nie ma czasu). W mowie potocznej częściej Konjunktiv II lub Indikativ.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Liczba mnoga rzeczowników — wzory', '5 typów: 1) -e: der Tisch → die Tische, 2) -er (+ Umlaut): das Kind → die Kinder, 3) -en/-n: die Frau → die Frauen, 4) - (bez zmian/Umlaut): der Vater → die Väter, 5) -s: das Auto → die Autos.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Infinitiv z ''zu''', 'Po wielu czasownikach/wyrażeniach: versuchen, anfangen, aufhören, es ist wichtig. Np. ''Ich versuche, pünktlich zu kommen.'' Przy trennbare Verben: ''zu'' wpada do środka: ''anzufangen'', ''aufzuhören''.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('um...zu + Infinitiv (cel)', 'Wyrażenie celu — żeby/aby. Np. ''Ich lerne Deutsch, um in Deutschland zu arbeiten.'' (Uczę się niemieckiego, żeby pracować w Niemczech). Podmiot musi być ten sam w obu częściach.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('damit — zdanie celowe (różne podmioty)', 'Kiedy podmioty są różne, używamy ''damit'' + zdanie poboczne: ''Ich erkläre es langsam, damit du es verstehst.'' (Wyjaśniam powoli, żebyś zrozumiał). Czasownik na końcu.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('obwohl vs trotzdem', '''obwohl'' — spójnik podrzędny (czasownik na końcu): ''Obwohl es regnet, gehe ich raus.'' ''trotzdem'' — przysłówek łączący (inwersja po nim): ''Es regnet, trotzdem gehe ich raus.'' Oba = mimo że.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('deshalb / deswegen / darum', 'Wszystkie znaczą ''dlatego'' i powodują inwersję. Np. ''Ich bin müde, deshalb gehe ich ins Bett.'' ''Er hatte Hunger, deswegen hat er etwas gegessen.''', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dzierżawcze — odmiana', 'mein, dein, sein, ihr, unser, euer, ihr, Ihr. Odmieniają się jak ''ein'': mein Hund (Nom. m.), meinen Hund (Akk. m.), meinem Hund (Dat. m.), meines Hundes (Gen. m.).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('n-Deklination', 'Niektóre rzeczowniki męskie dodają -n/-en we wszystkich przypadkach oprócz Nominativ. Np. der Junge → den/dem/des Jungen. der Herr → den/dem Herrn / des Herrn. der Student → den/dem/des Studenten.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przyimki z Genitiv', 'wegen (z powodu), während (podczas), trotz (mimo), statt/anstatt (zamiast), innerhalb (wewnątrz), außerhalb (poza). Np. ''wegen des Wetters'', ''während der Pause'', ''trotz des Regens''.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('je...desto / je...umso', 'Im..., tym... Budowa: je + Komparativ..., desto/umso + Komparativ (+ inwersja). Np. ''Je mehr ich lerne, desto besser verstehe ich.'' (Im więcej się uczę, tym lepiej rozumiem).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('lassen — znaczenia i użycie', '1) Pozwolić: ''Lass mich gehen.'' 2) Kazać/zlecić: ''Ich lasse mein Auto reparieren.'' (= każ naprawić). 3) Zostawić: ''Lass das Buch auf dem Tisch.'' Perfekt: ''Ich habe das Auto reparieren lassen.''', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('die Besprechung / die Sitzung', 'Spotkanie / zebranie. Np. ''Die Besprechung findet um 10 Uhr statt.'' (Spotkanie odbywa się o 10).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Termin', 'Termin / umówione spotkanie. Np. ''Ich habe morgen einen Termin beim Arzt.'' Też: deadline — ''der Abgabetermin''.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Bewerbung', 'Aplikacja / podanie o pracę. Np. ''Ich schicke meine Bewerbung per E-Mail.'' sich bewerben = aplikować.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Lebenslauf', 'CV / życiorys. Np. ''Bitte fügen Sie Ihren Lebenslauf bei.'' (Proszę dołączyć CV).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Vorstellungsgespräch', 'Rozmowa kwalifikacyjna. Np. ''Ich wurde zum Vorstellungsgespräch eingeladen.'' (Zostałem zaproszony na rozmowę kwalifikacyjną).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Umsatz', 'Obrót / przychód ze sprzedaży. Np. ''Der Umsatz ist um 20% gestiegen.'' (Przychód wzrósł o 20%).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Gewinn', 'Zysk. Np. ''Das Unternehmen hat einen Gewinn von 5 Millionen Euro erzielt.'' der Verlust = strata (przeciwieństwo).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Rechnung', 'Faktura / rachunek. Np. ''Bitte senden Sie mir die Rechnung.'' (Proszę przesłać mi fakturę). eine Rechnung ausstellen = wystawić fakturę.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Abteilung', 'Dział / oddział w firmie. Np. ''Ich arbeite in der Marketingabteilung.'' (Pracuję w dziale marketingu).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Geschäftsführer', 'Dyrektor zarządzający / prezes. Np. ''Der Geschäftsführer leitet das Unternehmen.'' die Geschäftsführerin (ż.).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Verhandlung', 'Negocjacja. Np. ''Die Verhandlungen waren erfolgreich.'' (Negocjacje zakończyły się sukcesem). verhandeln = negocjować.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Vertrag', 'Umowa / kontrakt. Np. ''Wir haben den Vertrag unterschrieben.'' (Podpisaliśmy umowę). einen Vertrag kündigen = wypowiedzieć umowę.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Lieferkette', 'Łańcuch dostaw. Np. ''Die Lieferkette wurde durch die Pandemie unterbrochen.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Buchhaltung', 'Księgowość. Np. ''Die Buchhaltung erstellt den Jahresbericht.'' (Księgowość przygotowuje raport roczny). der Buchhalter = księgowy.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Überweisung', 'Przelew bankowy. Np. ''Die Überweisung wurde gestern ausgeführt.'' (Przelew został wykonany wczoraj). überweisen = przelać pieniądze.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sehr geehrte Damen und Herren', 'Szanowni Państwo — formalne zwroty na początek listu/e-maila, gdy nie znamy adresata. Odpowiednik ''Dear Sir or Madam''.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mit freundlichen Grüßen', 'Z poważaniem — formalne zakończenie listu/e-maila. Skrót: MfG. Odpowiednik ''Yours sincerely / Best regards''.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('im Anhang finden Sie', 'W załączeniu znajdą Państwo — formalna fraza e-mailowa. Np. ''Im Anhang finden Sie die gewünschten Unterlagen.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bezug nehmend auf', 'W nawiązaniu do — formalna fraza korespondencyjna. Np. ''Bezug nehmend auf Ihr Schreiben vom 15. März...''', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Frist', 'Termin / deadline. Np. ''Die Frist läuft am Freitag ab.'' (Termin upływa w piątek). eine Frist einhalten = dotrzymać terminu. eine Frist verlängern = przedłużyć termin.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Bestellung', 'Zamówienie. Np. ''Wir haben Ihre Bestellung erhalten.'' (Otrzymaliśmy Państwa zamówienie). bestellen = zamawiać.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Lieferung', 'Dostawa. Np. ''Die Lieferung erfolgt innerhalb von 5 Werktagen.'' (Dostawa w ciągu 5 dni roboczych). liefern = dostarczać.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Kunde / die Kundin', 'Klient / klientka. Np. ''Der Kunde ist König.'' (Klient jest królem). die Kundenzufriedenheit = satysfakcja klienta.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Zusammenarbeit', 'Współpraca. Np. ''Wir freuen uns auf die Zusammenarbeit.'' (Cieszymy się na współpracę). zusammenarbeiten = współpracować.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Schulung', 'Szkolenie. Np. ''Die Schulung findet nächste Woche statt.'' (Szkolenie odbywa się w przyszłym tygodniu). schulen = szkolić.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Ansprechpartner', 'Osoba kontaktowa / odpowiedzialna. Np. ''Ihr Ansprechpartner ist Herr Müller.'' (Państwa osoba kontaktowa to Pan Müller).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Mahnung', 'Wezwanie do zapłaty / ponaglenie. Np. ''Wir mussten eine Mahnung schicken.'' (Musieliśmy wysłać wezwanie do zapłaty). mahnen = upominać.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Tagesordnung', 'Porządek obrad — lista tematów na spotkaniu. Np. ''Der erste Punkt auf der Tagesordnung ist...'' (Pierwszy punkt porządku obrad to...).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Protokoll', 'Protokół / notatka ze spotkania. Np. ''Wer schreibt heute das Protokoll?'' (Kto dziś pisze protokół?).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Vorschlag', 'Propozycja / wniosek. Np. ''Ich habe einen Vorschlag.'' (Mam propozycję). vorschlagen = proponować.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Aufgabe', 'Zadanie / obowiązek. Np. ''Meine Aufgabe ist die Kundenkommunikation.'' (Moim zadaniem jest komunikacja z klientami).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('zuständig sein für', 'Być odpowiedzialnym za. Np. ''Ich bin für den Vertrieb zuständig.'' (Jestem odpowiedzialny za sprzedaż). die Zuständigkeit = kompetencja/zakres obowiązków.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Gehaltserhöhung', 'Podwyżka. Np. ''Er hat um eine Gehaltserhöhung gebeten.'' (Poprosił o podwyżkę). das Gehalt = wynagrodzenie (miesięczne).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('kündigen', 'Wypowiedzieć (umowę, pracę). Np. ''Sie hat gekündigt.'' (Złożyła wypowiedzenie). die Kündigung = wypowiedzenie. die Kündigungsfrist = okres wypowiedzenia.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Besprechungsnotiz', 'Notatka ze spotkania. Np. ''Ich schicke Ihnen die Besprechungsnotiz per E-Mail.'' (Wyślę Państwu notatkę ze spotkania e-mailem).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('das Angebot', 'Oferta. Np. ''Wir unterbreiten Ihnen folgendes Angebot.'' (Przedstawiamy Państwu następującą ofertę). ein Angebot machen = złożyć ofertę.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Anfrage', 'Zapytanie (ofertowe). Np. ''Vielen Dank für Ihre Anfrage.'' (Dziękujemy za zapytanie). anfragen = zapytać.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Zielgruppe', 'Grupa docelowa. Np. ''Unsere Zielgruppe sind junge Berufstätige.'' (Naszą grupą docelową są młodzi profesjonaliści).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('die Marktanalyse', 'Analiza rynku. Np. ''Die Marktanalyse zeigt positive Trends.'' (Analiza rynku pokazuje pozytywne trendy). der Markt = rynek.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('der Wettbewerb', 'Konkurencja / konkurs. Np. ''Der Wettbewerb auf dem Markt ist stark.'' (Konkurencja na rynku jest silna). der Wettbewerber = konkurent.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Ser vs Estar — kiedy ser?', 'Ser — tożsamość, zawód, pochodzenie, cechy stałe, materiał, czas, wydarzenia. Np. ''Soy polaco.'' ''Es médico.'' ''La mesa es de madera.'' ''Son las tres.'' Pamięć: DOCTOR — Description, Occupation, Characteristic, Time, Origin, Relationship.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ser vs Estar — kiedy estar?', 'Estar — lokalizacja, stan tymczasowy, emocje, wynik czynności, gerundio. Np. ''Estoy en casa.'' ''Estoy cansado.'' ''La puerta está abierta.'' ''Estoy leyendo.'' Pamięć: PLACE — Position, Location, Action, Condition, Emotion.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ser vs Estar — zmiana znaczenia', 'Niektóre przymiotniki zmieniają znaczenie: ser listo = być bystrym, estar listo = być gotowym. ser aburrido = być nudnym, estar aburrido = być znudzonym. ser malo = być złym, estar malo = być chorym.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de indicativo — czasowniki regularne', '-ar: hablo, hablas, habla, hablamos, habláis, hablan. -er: como, comes, come, comemos, coméis, comen. -ir: vivo, vives, vive, vivimos, vivís, viven.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito indefinido — kiedy?', 'Czynności zakończone w przeszłości w określonym czasie. Np. ''Ayer comí paella.'' ''Viajé a España en 2020.'' Określniki: ayer, anoche, la semana pasada, el año pasado, hace dos días.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito imperfecto — kiedy?', 'Opisy w przeszłości, czynności powtarzające się, nawyki, tło wydarzeń. Np. ''Cuando era niño, jugaba al fútbol.'' ''Hacía sol y los pájaros cantaban.'' Końcówki -ar: -aba, -abas, -aba, -ábamos, -abais, -aban.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Indefinido vs Imperfecto', 'Indefinido = pojedyncze, zakończone zdarzenie: ''Ayer llovió.'' Imperfecto = tło, opis, nawyk: ''Cuando llegué, llovía.'' Razem: ''Leía un libro cuando sonó el teléfono.'' (impf + indef).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito perfecto — budowa i użycie', 'haber (he, has, ha, hemos, habéis, han) + participio (-ado/-ido). Czynności powiązane z teraźniejszością. Np. ''Hoy he comido mucho.'' ''Este año hemos viajado a Italia.'' Określniki: hoy, esta semana, este mes, ya, todavía no.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Participio pasado — formy nieregularne', 'Najważniejsze nieregularne: hacer → hecho, decir → dicho, escribir → escrito, ver → visto, volver → vuelto, poner → puesto, abrir → abierto, morir → muerto, romper → roto.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futuro simple — budowa', 'Bezokolicznik + końcówki: -é, -ás, -á, -emos, -éis, -án. Np. ''Mañana hablaré con él.'' Nieregularne rdzenie: tener → tendr-, poder → podr-, saber → sabr-, hacer → har-, decir → dir-.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Condicional simple — budowa i użycie', 'Bezokolicznik + -ía, -ías, -ía, -íamos, -íais, -ían. Użycie: życzenia, rady, hipotetyczne sytuacje. Np. ''Me gustaría viajar.'' ''¿Podrías ayudarme?'' Te same nieregularne rdzenie co w futuro.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjuntivo — co to jest i kiedy?', 'Tryb łączący — wyrażanie życzenia, emocji, wątpliwości, polecenia, opinii negatywnej. Po: querer que, esperar que, es importante que, no creo que, ojalá. Np. ''Quiero que vengas.'' ''Espero que estés bien.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de subjuntivo — odmiana regularna', '-ar: hable, hables, hable, hablemos, habléis, hablen. -er/-ir: coma, comas, coma, comamos, comáis, coman. Zamiana samogłoski: -ar → -e, -er/-ir → -a.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Presente de subjuntivo — formy nieregularne', 'Oparte na 1. os. presente: tener → tenga, poner → ponga, salir → salga, venir → venga, decir → diga, hacer → haga. Wyjątki: ser → sea, ir → vaya, haber → haya, saber → sepa, dar → dé.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Por vs Para', '''Por'' — przyczyna, zamiana, ''przez'' (czas/miejsce), środek: ''por la mañana'', ''gracias por todo'', ''por correo''. ''Para'' — cel, odbiorca, termin, ''dla'': ''para ti'', ''para aprender'', ''para el lunes''.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dopełnienia bliższego (OD)', 'me, te, lo/la, nos, os, los/las. Stawiamy PRZED czasownikiem: ''Lo veo.'' (Widzę go). Z bezokolicznikiem/gerundio: na końcu: ''Quiero verlo.'' ''Estoy leyéndolo.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki dopełnienia dalszego (OI)', 'me, te, le, nos, os, les. Np. ''Le doy el libro.'' (Daję mu/jej książkę). Gdy OI + OD razem: le/les → se: ''Se lo doy.'' (Daję mu to). Kolejność: OI + OD + czasownik.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gustar i podobne czasowniki', 'Budowa: OI + gustar + podmiot. ''Me gusta el café.'' (Podoba mi się kawa). ''Me gustan los libros.'' (l.mn.). Podobne: encantar, molestar, importar, interesar, doler, faltar, quedar.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki zwrotne (reflexivos)', 'Zaimki: me, te, se, nos, os, se + czasownik. Np. ''Me levanto a las 7.'' (Wstaję o 7). ''Se llama María.'' Wiele czasowników zmienia znaczenie: ir = iść, irse = odejść; dormir = spać, dormirse = zasnąć.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gerundio — budowa i użycie', '-ar → -ando (hablando), -er/-ir → -iendo (comiendo, viviendo). Nieregularne: leer → leyendo, dormir → durmiendo, decir → diciendo. Użycie z estar: ''Estoy estudiando.'' (Właśnie się uczę).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativo afirmativo — formy tú', 'Regularne = 3. os. l.p. presente: habla, come, escribe. Nieregularne: tener → ten, venir → ven, salir → sal, hacer → haz, poner → pon, ir → ve, decir → di, ser → sé.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperativo negativo', 'No + presente de subjuntivo. Np. ''¡No hables!'' ''¡No comas!'' ''¡No vengas!'' Obowiązuje dla WSZYSTKICH osób: ''¡No hable usted!'' ''¡No habléis!''', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Perífrasis verbales — najważniejsze', 'ir a + infinitivo = zamierzać: ''Voy a estudiar.'' tener que + inf. = musieć: ''Tengo que irme.'' deber + inf. = powinien: ''Debes estudiar.'' estar + gerundio = trwanie: ''Estoy comiendo.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pluscuamperfecto — budowa', 'había/habías/había/habíamos/habíais/habían + participio. Czynność przed inną w przeszłości. Np. ''Cuando llegué, ella ya había salido.'' (Gdy dotarłem, ona już wyszła).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzaj gramatyczny rzeczowników — zasady', 'Męskie: -o (el libro), -ma (el problema, el tema, el sistema). Żeńskie: -a (la mesa), -ción/-sión (la nación), -dad/-tad (la ciudad). Wyjątki: la mano (ż.), el día (m.), el mapa (m.).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Liczba mnoga — zasady', 'Samogłoska → + -s: libro → libros. Spółgłoska → + -es: ciudad → ciudades. -z → -ces: vez → veces, lápiz → lápices. Akcentowane: café → cafés, menú → menús.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotniki — pozycja i odmiana', 'Zazwyczaj PO rzeczowniku: ''un coche rojo'' (czerwony samochód). Przed — zmiana znaczenia: ''un gran hombre'' (wielki) vs ''un hombre grande'' (duży). Odmiana: -o/-a/-os/-as lub -e/-es.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'Comparativo: más...que (więcej niż), menos...que (mniej niż), tan...como (tak jak). Superlativo: el/la más + adj. Nieregularne: bueno → mejor, malo → peor, grande → mayor, pequeño → menor.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Preposiciones: a, en, de', '''a'' — kierunek, odbiorca, godzina: ''Voy a Madrid.'' ''a las tres''. ''en'' — miejsce, środek transportu: ''Estoy en casa.'' ''en coche''. ''de'' — pochodzenie, posiadanie, materiał: ''Soy de Polonia.'' ''el libro de Juan.''', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('A personal (a osobowe)', 'Przed dopełnieniem osobowym (osobą) stawiamy ''a'': ''Veo a María.'' ''Llamo a mi madre.'' NIE z rzeczami: ''Veo la película.'' NIE z hay: ''Hay muchas personas.''', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oraciones condicionales — typ 1 (realne)', 'Si + presente, futuro/presente/imperativo. Np. ''Si llueve, no saldremos.'' ''Si tienes hambre, come algo.'' Nie używamy futuro po ''si''!', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Oraciones condicionales — typ 2 (nierealne)', 'Si + imperfecto de subjuntivo, condicional. Np. ''Si tuviera dinero, viajaría por el mundo.'' (Gdybym miał pieniądze, podróżowałbym po świecie).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imperfecto de subjuntivo — budowa', 'Od 3. os. l.mn. indefinido: hablaron → habla-ra/habla-se. Dwie formy: -ra/-ras/-ra/-ramos/-rais/-ran LUB -se/-ses/-se/-semos/-seis/-sen. Forma -ra częstsza. Np. pudiera / pudiese.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki z oboczną samogłoską (e→ie, o→ue)', 'e→ie: pensar → pienso, querer → quiero, preferir → prefiero. o→ue: poder → puedo, dormir → duermo, volver → vuelvo. Zmiana w os. akcentowanych (nie w nosotros/vosotros).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Estar + participio (stan wynikowy)', 'Opisuje stan będący wynikiem czynności. Np. ''La puerta está cerrada.'' (Drzwi są zamknięte). ''El libro está escrito en español.'' Participio odmienia się jak przymiotnik (-o/-a/-os/-as).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Voz pasiva — strona bierna', 'ser + participio (+ por). Np. ''El libro fue escrito por Cervantes.'' Hiszpański preferuje stronę czynną lub ''se'' pasywne: ''Se habla español aquí.'' (Mówi się tu po hiszpańsku).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito indefinido — formy nieregularne', 'tener → tuve, estar → estuve, poder → pude, poner → puse, saber → supe, hacer → hice, venir → vine, querer → quise, decir → dije, traer → traje. Ser/Ir → fui, fuiste, fue, fuimos, fuisteis, fueron.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Muy vs Mucho', '''Muy'' + przymiotnik/przysłówek: ''muy grande'', ''muy bien''. ''Mucho'' + rzeczownik / samodzielnie / z czasownikiem: ''mucho dinero'', ''como mucho''. NIE: ''muy mucho''. Odmiana: mucho/mucha/muchos/muchas (przed rzeczownikiem).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Saber vs Conocer', '''Saber'' — wiedzieć, umieć (fakty, umiejętności): ''Sé nadar.'' ''No sé dónde está.'' ''Conocer'' — znać (osoby, miejsca, doświadczać): ''Conozco Madrid.'' ''¿Conoces a Juan?''', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pedir vs Preguntar', '''Pedir'' — prosić o coś: ''Pedí un café.'' ''Te pido un favor.'' ''Preguntar'' — pytać o informację: ''Le pregunté la hora.'' ''Pregunta si viene.''', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Quedar vs Quedarse', '''Quedar'' — umawiać się / pozostawać: ''Quedamos a las cinco.'' ''Me quedan dos euros.'' ''Quedarse'' — zostać (w miejscu): ''Me quedé en casa.'' ''Quédate aquí.''', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Desde / Desde hace / Hace...que', '''Desde'' + punkt w czasie: ''Vivo aquí desde 2010.'' ''Desde hace'' + okres: ''Vivo aquí desde hace 5 años.'' ''Hace...que'' + presente: ''Hace 5 años que vivo aquí.'' Wszystkie = od (pewnego czasu).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aunque + indicativo vs subjuntivo', '''Aunque'' + indicativo = chociaż (fakt): ''Aunque llueve, salgo.'' ''Aunque'' + subjuntivo = nawet jeśli (hipotetycznie): ''Aunque llueva, saldré.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cuando + subjuntivo (przyszłość)', 'Po ''cuando'' odnoszącym się do przyszłości → subjuntivo: ''Cuando tenga tiempo, te llamaré.'' (Kiedy będę miał czas, zadzwonię). Przeszłość/teraźniejszość → indicativo: ''Cuando era joven...''', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ojalá + subjuntivo', '''Ojalá'' — wyrażanie życzenia. + presente subj. (możliwe): ''Ojalá venga.'' (Oby przyszedł). + imperfecto subj. (mało prawdopodobne): ''Ojalá pudiera volar.'' (Chciałbym móc latać).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Hay vs Está/Están', '''Hay'' — istnienie (coś jest gdzieś, nieokreślone): ''Hay un banco en la esquina.'' ''Está/Están'' — lokalizacja (czegoś określonego): ''El banco está en la esquina.'' Nie: ''Hay el banco.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Llevar + gerundio (trwanie)', 'Wyrażenie czasu trwania czynności. Np. ''Llevo dos años estudiando español.'' (Od dwóch lat uczę się hiszpańskiego). ''¿Cuánto tiempo llevas viviendo aquí?'' Odpowiednik ang. ''have been doing''.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acabar de + infinitivo', 'Właśnie coś zrobić — niedawno zakończona czynność. Np. ''Acabo de comer.'' (Właśnie zjadłem). ''Acabamos de llegar.'' (Właśnie dotarliśmy). Imperfecto: ''Acababa de salir cuando llamaste.''', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Soler + infinitivo (zwyczaj)', 'Mieć zwyczaj / zazwyczaj coś robić. Np. ''Suelo desayunar a las 8.'' (Zwykle jadam śniadanie o 8). ''Solía jugar al fútbol.'' (Miałem zwyczaj grać w piłkę). Nie ma formy futuro.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pretérito perfecto de subjuntivo', 'haya/hayas/haya/hayamos/hayáis/hayan + participio. Po wyrażeniach wymagających subjuntivo, gdy czynność jest zakończona. Np. ''Espero que hayan llegado bien.'' (Mam nadzieję, że dobrze dotarli).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('el aeropuerto', 'Lotnisko. Np. ''¿Cómo llego al aeropuerto?'' (Jak dojadę na lotnisko?).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la tarjeta de embarque', 'Karta pokładowa. Np. ''Aquí tiene su tarjeta de embarque.'' (Proszę, oto Pana/Pani karta pokładowa).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el equipaje / la maleta', 'Bagaż / walizka. Np. ''He perdido mi equipaje.'' (Zgubiłem bagaż). ''Voy a facturar la maleta.'' (Nadam walizkę).', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la puerta de embarque', 'Bramka (na lotnisku). Np. ''La puerta de embarque es la B12.'' (Bramka to B12).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el vuelo', 'Lot. Np. ''Mi vuelo sale a las 10.'' (Mój lot odlatuje o 10). ''El vuelo tiene retraso.'' (Lot jest opóźniony).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la reserva', 'Rezerwacja. Np. ''Tengo una reserva a nombre de García.'' (Mam rezerwację na nazwisko García). reservar = zarezerwować.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la habitación individual / doble', 'Pokój jednoosobowy / dwuosobowy. Np. ''Quisiera una habitación doble con vistas al mar.'' (Chciałbym pokój dwuosobowy z widokiem na morze).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿A qué hora es el check-in?', 'O której jest zameldowanie? Np. ''El check-in es a partir de las 14:00.'' (Zameldowanie od 14:00). la llegada = przyjazd, la salida = wymeldowanie/wyjazd.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Está incluido el desayuno?', 'Czy śniadanie jest wliczone? Np. ''Sí, el desayuno está incluido en el precio.'' (Tak, śniadanie jest wliczone w cenę).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la llave / la tarjeta de la habitación', 'Klucz / karta do pokoju. Np. ''He dejado la llave dentro de la habitación.'' (Zostawiłem klucz w pokoju).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Tiene una mesa para dos?', 'Czy jest stolik dla dwóch osób? Np. ''Buenas noches, ¿tiene una mesa para dos?'' (Dobry wieczór, czy jest stolik dla dwojga?).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la carta / el menú', 'Menu / karta dań. Np. ''¿Me puede traer la carta, por favor?'' (Czy mogę prosić o kartę?). el menú del día = zestaw dnia.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Qué me recomienda?', 'Co Pan/Pani poleca? Np. ''¿Qué plato me recomienda?'' (Jakie danie Pan poleca?). la especialidad de la casa = specjalność zakładu.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('La cuenta, por favor', 'Poproszę rachunek. Np. ''¿Nos trae la cuenta, por favor?'' (Czy może nam Pan przynieść rachunek?). pagar = zapłacić, la propina = napiwek.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Soy alérgico/a a...', 'Jestem uczulony/a na... Np. ''Soy alérgico a los frutos secos.'' (Jestem uczulony na orzechy). ''¿Contiene gluten?'' (Czy zawiera gluten?).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Dónde está la estación de tren?', 'Gdzie jest dworzec kolejowy? Np. ''¿Podría indicarme dónde está la estación de tren?'' (Czy mógłby mi Pan wskazać, gdzie jest dworzec?).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('un billete de ida / de ida y vuelta', 'Bilet w jedną stronę / w obie strony. Np. ''Quisiera un billete de ida y vuelta a Barcelona.'' (Chciałbym bilet powrotny do Barcelony).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿A qué hora sale el próximo tren?', 'O której odjeżdża następny pociąg? Np. ''El próximo tren sale a las 15:30, andén 4.'' (Następny pociąg odjeżdża o 15:30, peron 4). el andén = peron.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Cuánto cuesta...?', 'Ile kosztuje...? Np. ''¿Cuánto cuesta la entrada al museo?'' (Ile kosztuje wejście do muzeum?). ''¿Cuánto es en total?'' (Ile to razem?).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Se puede pagar con tarjeta?', 'Czy można zapłacić kartą? Np. ''¿Aceptan tarjeta de crédito?'' (Czy przyjmujecie kartę kredytową?). en efectivo = gotówką.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Podría hablar más despacio?', 'Czy mógłby Pan mówić wolniej? Np. ''Lo siento, no entiendo. ¿Podría hablar más despacio, por favor?'' Przydatne, gdy nie rozumiemy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Cómo se llega a...?', 'Jak się dostać do...? Np. ''¿Cómo se llega al centro de la ciudad?'' (Jak dojść do centrum?). todo recto = prosto, a la derecha/izquierda = w prawo/lewo.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Estoy buscando...', 'Szukam... Np. ''Estoy buscando una farmacia.'' (Szukam apteki). ''Estoy buscando la oficina de turismo.'' (Szukam biura turystycznego).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el horario de apertura', 'Godziny otwarcia. Np. ''¿Cuál es el horario de apertura del museo?'' (Jakie są godziny otwarcia muzeum?). abierto = otwarte, cerrado = zamknięte.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la oficina de turismo', 'Biuro turystyczne. Np. ''¿Dónde está la oficina de turismo más cercana?'' (Gdzie jest najbliższe biuro turystyczne?). un mapa = mapa, un folleto = ulotka.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('alquilar un coche', 'Wynająć samochód. Np. ''Quisiera alquilar un coche para una semana.'' (Chciałbym wynająć samochód na tydzień). el alquiler = wynajem, el seguro = ubezpieczenie.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Hay una farmacia cerca?', 'Czy jest tu gdzieś blisko apteka? Np. ''Necesito una farmacia. ¿Hay una cerca de aquí?'' (Potrzebuję apteki. Czy jest jakaś w pobliżu?).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Necesito ayuda / un médico', 'Potrzebuję pomocy / lekarza. Np. ''¡Necesito un médico, por favor!'' la urgencia = nagły wypadek, el hospital = szpital. Numer alarmowy w UE: 112.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la playa', 'Plaża. Np. ''¿Cómo se llega a la playa?'' (Jak dojść na plażę?). la sombrilla = parasol, la toalla = ręcznik, la crema solar = krem z filtrem.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el supermercado', 'Supermarket. Np. ''¿Dónde hay un supermercado?'' (Gdzie jest supermarket?). la bolsa = torba, la caja = kasa.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Me he perdido', 'Zgubiłem się. Np. ''Disculpe, me he perdido. ¿Podría ayudarme?'' (Przepraszam, zgubiłem się. Czy mógłby mi Pan pomóc?).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Tiene WiFi?', 'Czy jest WiFi? Np. ''¿Tiene WiFi? ¿Cuál es la contraseña?'' (Czy jest WiFi? Jakie jest hasło?). la contraseña = hasło.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la propina', 'Napiwek. W Hiszpanii napiwek nie jest obowiązkowy, ale mile widziany. Np. ''¿Se deja propina aquí?'' (Czy zostawia się tu napiwek?). Zazwyczaj 5-10% w restauracji.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¿Me puede dar un recibo?', 'Czy mogę prosić o paragon? Np. ''¿Me puede dar un recibo, por favor?'' la factura = faktura (biznesowa).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el cambio de moneda', 'Wymiana walut. Np. ''¿Dónde puedo cambiar dinero?'' (Gdzie mogę wymienić pieniądze?). la casa de cambio = kantor. el tipo de cambio = kurs wymiany.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hacer una excursión', 'Pojechać na wycieczkę. Np. ''¿Hay excursiones organizadas?'' (Czy są wycieczki zorganizowane?). la visita guiada = zwiedzanie z przewodnikiem. el guía = przewodnik.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('sacar fotos / hacer fotos', 'Robić zdjęcia. Np. ''¿Se pueden sacar fotos aquí?'' (Czy można tu robić zdjęcia?). ''¿Podría hacernos una foto?'' (Czy mógłby nam Pan zrobić zdjęcie?).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('¡Que tengas buen viaje!', 'Miłej podróży! Formalnie: ''¡Que tenga buen viaje!'' Np. ''Gracias por todo. ¡Que tengas buen viaje!'' (Dziękuję za wszystko. Miłej podróży!).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('el pasaporte / el DNI', 'Paszport / dowód osobisty. Np. ''¿Tiene su pasaporte?'' (Czy ma Pan paszport?). DNI = Documento Nacional de Identidad. el visado = wiza.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la aduana', 'Odprawa celna. Np. ''¿Tiene algo que declarar en la aduana?'' (Czy ma Pan coś do oclenia?). declarar = zgłosić do cła. el control de pasaportes = kontrola paszportowa.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Présent — odmiana czasowników I grupy (-er)', 'Rdzeń + -e, -es, -e, -ons, -ez, -ent. Np. parler: je parle, tu parles, il parle, nous parlons, vous parlez, ils parlent. Uwaga: końcówki -e, -es, -ent są nieme!', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Présent — odmiana czasowników II grupy (-ir)', 'Rdzeń + -is, -is, -it, -issons, -issez, -issent. Np. finir: je finis, tu finis, il finit, nous finissons, vous finissez, ils finissent. Dotyczy: choisir, réussir, rougir.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Être i avoir — odmiana w présent', 'Être: je suis, tu es, il est, nous sommes, vous êtes, ils sont. Avoir: j''ai, tu as, il a, nous avons, vous avez, ils ont. Dwa najważniejsze czasowniki — czasowniki posiłkowe.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé — budowa', 'avoir/être + participe passé. Np. ''J''ai mangé.'' ''Elle est partie.'' Z être: czasowniki ruchu/zwrotne (DR MRS VANDERTRAMP): aller, venir, partir, arriver, naître, mourir, rester, sortir, entrer, descendre, monter, tomber, retourner.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé z être — zgodność', 'Participe passé zgadza się z podmiotem w rodzaju i liczbie: ''Elle est allée.'' ''Ils sont partis.'' ''Elles sont venues.'' +e (ż.), +s (l.mn.), +es (ż. l.mn.).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Participe passé — formy nieregularne', 'être → été, avoir → eu, faire → fait, prendre → pris, mettre → mis, dire → dit, écrire → écrit, voir → vu, lire → lu, savoir → su, pouvoir → pu, vouloir → voulu, venir → venu, ouvrir → ouvert.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Imparfait — budowa i użycie', 'Rdzeń z nous (présent) + -ais, -ais, -ait, -ions, -iez, -aient. Np. nous parlons → je parlais. Użycie: opisy, nawyki, tło. ''Quand j''étais petit, je jouais au foot.'' Wyjątek: être → j''étais (rdzeń ét-).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé composé vs Imparfait', 'PC = pojedyncze, zakończone zdarzenie: ''Hier, j''ai mangé une pizza.'' Imparfait = tło, opis, nawyk: ''Il faisait beau.'' Razem: ''Je lisais quand le téléphone a sonné.'' (imparfait + PC).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur simple — budowa', 'Bezokolicznik + -ai, -as, -a, -ons, -ez, -ont. Np. parler → je parlerai. Nieregularne rdzenie: être → ser-, avoir → aur-, faire → fer-, aller → ir-, pouvoir → pourr-, vouloir → voudr-, venir → viendr-.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur proche — budowa i użycie', 'aller (odmieniony) + infinitif. Bliska przyszłość, plany. Np. ''Je vais partir demain.'' ''Il va pleuvoir.'' Odpowiednik ang. ''going to''. Częstszy w mowie niż futur simple.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Conditionnel présent — budowa i użycie', 'Rdzeń futur simple + końcówki imparfait: -ais, -ais, -ait, -ions, -iez, -aient. Np. je parlerais, j''aurais, je serais. Użycie: grzeczne prośby, życzenia, hipotetyczne sytuacje. ''Je voudrais un café.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajnik określony: le, la, l'', les', 'le (r.m.): le livre. la (r.ż.): la table. l'' (przed samogłoską/h niemym): l''ami, l''heure. les (l.mn.): les enfants. Używamy z rzeczami ogólnymi: ''J''aime le chocolat.''', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Rodzajnik nieokreślony i cząstkowy', 'un/une/des (nieokreślony): ''J''ai un chat.'' du/de la/de l''/des (cząstkowy — pewna ilość): ''Je mange du pain.'' ''Je bois de l''eau.'' W przeczeniu → de/d'': ''Je n''ai pas de pain.''', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przeczenie: ne...pas i inne', 'ne...pas: ''Je ne mange pas.'' ne...plus: już nie — ''Je ne fume plus.'' ne...jamais: nigdy — ''Il ne ment jamais.'' ne...rien: nic — ''Je ne vois rien.'' ne...personne: nikt — ''Il ne connaît personne.''', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki osobowe — COD (dopełnienie bliższe)', 'me, te, le/la, nous, vous, les. Przed czasownikiem: ''Je le vois.'' (Widzę go). ''Il les achète.'' (On je kupuje). PC: ''Je l''ai vu.'' (Widziałem go/ją).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki osobowe — COI (dopełnienie dalsze)', 'me, te, lui, nous, vous, leur. Przed czasownikiem: ''Je lui parle.'' (Mówię do niego/niej). ''Il leur donne un cadeau.'' (Daje im prezent). Kolejność: COI + COD + verbe (ale me/te/nous/vous przed le/la/les).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki Y i EN', '''Y'' zastępuje miejsce (à + rzecz): ''J''y vais.'' (Idę tam). ''J''y pense.'' (Myślę o tym). ''EN'' zastępuje de + rzecz lub ilość: ''J''en veux.'' (Chcę tego). ''J''en ai trois.'' (Mam trzy).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif — kiedy go używamy?', 'Po wyrażeniach: życzenia (je veux que), emocji (je suis content que), wątpliwości (je doute que), konieczności (il faut que), opinii negatywnej (je ne pense pas que). Np. ''Il faut que tu viennes.''', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif présent — odmiana regularna', 'Rdzeń z ils/elles (présent) + -e, -es, -e, -ions, -iez, -ent. Np. ils parlent → que je parle, que tu parles. Nous/vous: rdzeń z nous présent: que nous parlions, que vous parliez.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Subjonctif — formy nieregularne', 'être: que je sois, que nous soyons. avoir: que j''aie, que nous ayons. aller: que j''aille, que nous allions. faire: que je fasse. pouvoir: que je puisse. savoir: que je sache. vouloir: que je veuille.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Si + imparfait, conditionnel (2. tryb)', 'Nierealna sytuacja teraźniejsza. Np. ''Si j''avais de l''argent, je voyagerais.'' (Gdybym miał pieniądze, podróżowałbym). Nie używamy conditionnel po ''si''. Si + imparfait → conditionnel présent.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Si + plus-que-parfait, conditionnel passé', 'Nierealna sytuacja przeszła. Np. ''Si j''avais étudié, j''aurais réussi.'' (Gdybym się uczył, zdałbym). Conditionnel passé = aurais/serais + participe passé.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Plus-que-parfait — budowa', 'Avoir/être w imparfait + participe passé. Czynność przed inną w przeszłości. Np. ''Il avait déjà mangé quand je suis arrivé.'' (Już zjadł, kiedy przyjechałem). ''Elle était partie.''', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Zaimki względne: qui, que, où, dont', '''qui'' — podmiot: ''L''homme qui parle.'' ''que'' — dopełnienie: ''Le livre que je lis.'' ''où'' — miejsce/czas: ''La ville où j''habite.'' ''dont'' — de + coś: ''Le film dont je parle.'' (o którym mówię).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotnik — pozycja we francuskim', 'Zazwyczaj PO rzeczowniku: ''une voiture rouge'' (czerwony samochód). Przed rzeczownikiem: BANGS — Beauty (beau), Age (jeune, vieux), Number (premier), Goodness (bon, mauvais), Size (grand, petit).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Przymiotnik — zgodność w rodzaju i liczbie', 'Podstawowa reguła: +e (żeński), +s (l.mn.), +es (ż. l.mn.). Np. grand → grande → grands → grandes. Wyjątki: beau → belle, vieux → vieille, nouveau → nouvelle. -eux → -euse: heureux → heureuse.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Stopniowanie przymiotników', 'plus...que (bardziej niż): ''Il est plus grand que moi.'' moins...que (mniej niż): ''C''est moins cher.'' aussi...que (tak samo jak): ''Elle est aussi intelligente que lui.'' Nieregularne: bon → meilleur, mauvais → pire.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Czasowniki zwrotne (verbes pronominaux)', 'Zaimki: me, te, se, nous, vous, se + czasownik. Np. ''Je me lève à 7h.'' (Wstaję o 7). W passé composé z être: ''Elle s''est levée.'' (zgodność!). se laver, se coucher, s''habiller, se souvenir.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Impératif — tryb rozkazujący', 'Trzy formy: tu, nous, vous. Bez zaimka podmiotowego. -er: Parle! Parlons! Parlez! -ir: Finis! Finissons! Finissez! Być: Sois! Soyons! Soyez! Mieć: Aie! Ayons! Ayez! Uwaga: -er bez ''s'' w tu: Mange! (nie Manges).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Passé récent — venir de + infinitif', 'Właśnie coś zrobić. Np. ''Je viens de manger.'' (Właśnie zjadłem). ''Il vient d''arriver.'' (Właśnie przyjechał). Odpowiednik ''have just done''.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Être en train de + infinitif', 'Trwanie czynności — odpowiednik ang. present continuous. Np. ''Je suis en train de lire.'' (Właśnie czytam). ''Il est en train de cuisiner.'' (On właśnie gotuje).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('C''est vs Il est', '''C''est'' + rodzajnik + rzeczownik / przymiotnik: ''C''est un professeur.'' ''C''est intéressant.'' ''Il est'' + przymiotnik (bez rodzajnika): ''Il est intelligent.'' ''Il est'' + zawód (bez rodzajnika): ''Il est médecin.''', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Strona bierna (voix passive)', 'être (w odpowiednim czasie) + participe passé + par. Np. ''Le livre est lu par les étudiants.'' ''La maison a été construite en 1900.'' Participe passé zgadza się z podmiotem.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mowa zależna (discours indirect)', 'Cofamy czasy: présent → imparfait, PC → plus-que-parfait, futur → conditionnel. Np. ''Je suis fatigué'' → Il a dit qu''il était fatigué. ''Je viendrai'' → Elle a dit qu''elle viendrait.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pytania — 3 sposoby', '1) Intonacja: ''Tu viens?'' 2) Est-ce que: ''Est-ce que tu viens?'' 3) Inwersja (formalnie): ''Viens-tu?'' Z zaimkami pytającymi: ''Où habites-tu?'' ''Qu''est-ce que tu fais?''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Depuis / Il y a / Pendant', '''Depuis'' = od (trwanie): ''J''habite ici depuis 5 ans.'' (présent!). ''Il y a'' = temu: ''Il y a 5 ans, j''ai déménagé.'' (PC). ''Pendant'' = przez (zakończone): ''J''ai étudié pendant 3 heures.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Gérondif — en + participe présent', 'Budowa: en + rdzeń nous présent + -ant. Np. ''en parlant'' (mówiąc), ''en mangeant'' (jedząc). Użycie: jednoczesność, sposób, warunek. ''J''écoute de la musique en travaillant.'' Wyjątki: en étant, en ayant, en sachant.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Qui est-ce qui / que / dont / où', 'Zaimki pytające złożone — kto/co (rozwinięte formy). Qui est-ce qui = kto (podmiot): ''Qui est-ce qui a appelé?'' Qu''est-ce que = co (dopełnienie): ''Qu''est-ce que tu fais?''', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Accord du participe passé z avoir', 'Z avoir: participe passé zgadza się z dopełnieniem bliższym, JEŚLI stoi ono PRZED czasownikiem. Np. ''Les fleurs que j''ai achetées.'' (kupiłem — kwiaty, r.ż. l.mn. → achetées). Bez COD przed = brak zgody.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tout / Toute / Tous / Toutes', 'tout + r.m. l.p.: ''tout le monde'' (cały świat). toute + r.ż. l.p.: ''toute la journée'' (cały dzień). tous + r.m. l.mn.: ''tous les jours'' (każdego dnia). toutes + r.ż. l.mn.: ''toutes les femmes''.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bien vs Bon', '''Bon'' = dobry (przymiotnik, z rzeczownikiem): ''un bon repas''. ''Bien'' = dobrze (przysłówek, z czasownikiem): ''Il parle bien français.'' Stopniowanie: bon → meilleur, bien → mieux.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Savoir vs Connaître', '''Savoir'' — wiedzieć, umieć (fakty, umiejętności): ''Je sais nager.'' ''Je sais qu''il est parti.'' ''Connaître'' — znać (osoby, miejsca): ''Je connais Paris.'' ''Tu connais Marie?'' Nie: ''Je sais Marie.''', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Devoir — znaczenia i użycie', '1) Musieć: ''Je dois partir.'' 2) Powinien (conditionnel): ''Tu devrais dormir.'' 3) Prawdopodobnie (present): ''Il doit être malade.'' 4) Być winnym: ''Je te dois 20 euros.''', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Il faut + infinitif / que + subjonctif', 'Bezosobowe ''trzeba''. + infinitif (ogólnie): ''Il faut travailler.'' (Trzeba pracować). + que + subjonctif (konkretna osoba): ''Il faut que tu partes.'' (Musisz odejść).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Quel / Quelle / Quels / Quelles', 'Zaimek pytający ''jaki/który'' — zgodny z rodzajem i liczbą. ''Quel livre?'' (m.l.p.) ''Quelle heure est-il?'' (ż.l.p.) ''Quels films?'' (m.l.mn.) ''Quelles idées?'' (ż.l.mn.).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Avant de + infinitif vs Après avoir/être + PP', '''Avant de'' + infinitif: ''Avant de partir, j''ai fermé la porte.'' (Zanim wyszedłem). ''Après avoir'' + PP: ''Après avoir mangé, je suis sorti.'' ''Après être parti(e), elle a pleuré.''', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ne...que = seulement (tylko)', 'Ograniczenie (nie jest to przeczenie!). Np. ''Je n''ai que 5 euros.'' = ''J''ai seulement 5 euros.'' (Mam tylko 5 euro). ''Il ne mange que des légumes.'' (Je tylko warzywa).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dont — zaimek względny (de)', 'Zastępuje ''de + rzeczownik'' w zdaniu względnym. Np. ''Le livre dont je parle'' (Książka, o której mówię — parler de). ''La fille dont le père est médecin'' (Dziewczyna, której ojciec jest lekarzem).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Futur antérieur — budowa', 'Avoir/être w futur simple + participe passé. Czynność zakończona przed inną w przyszłości. Np. ''Quand tu arriveras, j''aurai fini.'' (Gdy przyjedziesz, już skończę). Też: przypuszczenie: ''Il aura oublié.''', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Même — różne znaczenia', '1) Przymiotnik (ten sam): ''le même jour'' (tego samego dnia). 2) Z zaimkiem (sam): ''moi-même'' (ja sam). 3) Przysłówek (nawet): ''Même les enfants le savent.'' (Nawet dzieci to wiedzą). 4) quand même = mimo to.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('l''entrée (f.)', 'Przystawka — pierwsze danie. Np. ''Comme entrée, je prends la salade de chèvre chaud.'' (Na przystawkę biorę sałatkę z ciepłym kozim serem). Nie mylić z ang. ''entrée'' (= danie główne w USA).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le plat principal', 'Danie główne. Np. ''Le plat principal est un magret de canard.'' (Danie główne to pierś z kaczki). le plat du jour = danie dnia.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le dessert', 'Deser. Np. ''En dessert, je voudrais une crème brûlée.'' (Na deser poproszę crème brûlée). Popularne: tarte tatin, mousse au chocolat, île flottante.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le fromage', 'Ser. Francja ma ponad 400 rodzajów sera. Najsłynniejsze: Camembert, Brie, Roquefort, Comté, Chèvre. ''Un plateau de fromages'' = talerz serów (podawany przed deserem).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la baguette', 'Bagietka — tradycyjny francuski chleb, długi i chrupiący. Np. ''Je vais acheter une baguette à la boulangerie.'' Wpisana na listę UNESCO w 2022. une tranche = kromka.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le croissant', 'Rogalik — maślowe, warstwowe ciasto na śniadanie. Np. ''Un café et un croissant, s''il vous plaît.'' un pain au chocolat = rogalik z czekoladą. la viennoiserie = wypieki wiedeńskie.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la boulangerie', 'Piekarnia. Np. ''La boulangerie ouvre à 6h du matin.'' la pâtisserie = cukiernia. le/la boulanger(-ère) = piekarz/piekarka.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le vin rouge / blanc / rosé', 'Wino czerwone / białe / różowe. Np. ''Je voudrais un verre de vin rouge, s''il vous plaît.'' Regiony: Bordeaux, Bourgogne, Champagne, Loire, Alsace. un cru = rocznik/rodzaj wina.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le marché', 'Targ / rynek. Np. ''Le samedi, je vais au marché acheter des fruits et des légumes.'' (W sobotę idę na targ kupić owoce i warzywa). le marché aux puces = pchli targ.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('faire la cuisine / cuisiner', 'Gotować. Np. ''J''adore faire la cuisine le dimanche.'' (Uwielbiam gotować w niedzielę). une recette = przepis, un ingrédient = składnik, mijoter = dusić na wolnym ogniu.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la crème fraîche', 'Kwaśna śmietana / śmietanka — podstawa kuchni francuskiej. Używana do sosów, zup i deserów. Np. ''Ajoutez une cuillère de crème fraîche à la sauce.''', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le beurre', 'Masło — kluczowy składnik kuchni francuskiej. Np. ''La cuisine française utilise beaucoup de beurre.'' le beurre doux = masło słodkie, le beurre demi-sel = masło półsłone (Bretania).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''ail (m.) / l''oignon (m.) / l''échalote (f.)', 'Czosnek / cebula / szalotka — podstawa wielu francuskich dań. Np. ''Faites revenir l''ail et l''oignon dans du beurre.'' (Podsmażyć czosnek i cebulę na maśle).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la quiche lorraine', 'Tarta lotaryńska — otwarta tarta z jajkami, śmietanką, boczkiem i serem. Pochodzi z regionu Lotaryngii. la pâte brisée = ciasto kruche.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le coq au vin', 'Kogut w winie — klasyczne danie kuchni francuskiej: kurczak duszony w czerwonym winie z warzywami, grzybami i boczkiem. Tradycyjne danie z Burgundii.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la ratatouille', 'Ratatouille — prowansalskie danie warzywne z bakłażana, cukinii, papryki, pomidorów i ziół. Np. ''La ratatouille est un plat typiquement provençal.''', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la crêpe / la galette', 'Naleśnik. Crêpe = cienki, słodki (mąka pszenna). Galette = słony (mąka gryczana) — specjalność Bretanii. Np. ''Une crêpe au Nutella et une galette complète, s''il vous plaît.'' (complète = z szynką, serem i jajkiem).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Bon appétit !', 'Smacznego! Mówi się na początku posiłku. Uwaga: w bardzo formalnym savoir-vivre (etykieta) niektórzy uważają, że nie powinno się tego mówić. W codziennych sytuacjach jest to jednak powszechne i miłe.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Santé ! / Tchin-tchin !', 'Na zdrowie! (toast). ''Santé'' — formalne. ''Tchin-tchin'' — nieformalne. Zasada: patrzeć w oczy przy stukaniu się kieliszkami (niepatrzenie = 7 lat pecha, wg przesądu).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la bise', 'Całus w policzek na powitanie. Liczba zależy od regionu: 2 (Paryż), 3 (południe), 4 (niektóre regiony). Między znajomymi i rodziną. W pracy — zależy od relacji. Po pandemii mniej powszechna.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le pourboire', 'Napiwek. We Francji obsługa jest wliczona w cenę (service compris). Napiwek nie jest obowiązkowy, ale zostawienie drobnych jest mile widziane. Np. ''Gardez la monnaie.'' (Proszę zatrzymać resztę).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le savoir-vivre', 'Znajomość zasad dobrego zachowania / etykieta. Np. mówić ''bonjour'' wchodząc do sklepu, nie kłaść łokci na stole, nie prosić o keczup w restauracji, trzymać ręce na stole (nie na kolanach).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le café / un expresso / un allongé', 'Kawa. ''Un café'' we Francji = mała, mocna kawa (expresso). ''Un allongé'' = rozcieńczona (jak americano). ''Un café crème'' = z mlekiem (na śniadanie). ''Un décaféiné / un déca'' = bezkofeinowa.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''apéritif / l''apéro (m.)', 'Aperitif — drink i przekąski przed kolacją. Ważny rytuał społeczny. Popularne: kir (białe wino + likier z czarnej porzeczki), pastis (anyżowy alkohol z południa), champagne. ''On prend l''apéro?''', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le digestif', 'Digestif — alkohol po posiłku, wspomagający trawienie. Popularne: calvados (jabłkowy brandy), cognac, armagnac, eau-de-vie. Pije się powoli.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('une brasserie / un bistrot', 'Brasserie = duża restauracja z pełnym menu, zwykle otwarta cały dzień. Bistrot (bistro) = mała, przytulna restauracja z prostymi, tradycyjnymi daniami. Oba są typowe dla Francji.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('l''addition, s''il vous plaît', 'Poproszę rachunek. We Francji kelner nie przynosi rachunku automatycznie — trzeba poprosić. Np. ''L''addition, s''il vous plaît.'' Posiłek w restauracji może trwać 1,5-2 godziny.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('les herbes de Provence', 'Zioła prowansalskie — mieszanka: tymianek, rozmaryn, oregano, cząber, lawenda. Używane do mięs, ryb, warzyw grillowanych. Np. ''Assaisonnez avec des herbes de Provence.'' (Przyprawić ziołami prowansalskimi).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la soupe à l''oignon', 'Zupa cebulowa — tradycyjna paryska zupa: karmelizowana cebula w bulionie wołowym, zapiekana z grzankami i serem Gruyère. Podawana zwłaszcza zimą.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le foie gras', 'Pasztet z wątroby gęsiej lub kaczej — delikates świąteczny. Podawany z brioche lub tostem i konfiturą z fig. Np. ''Le foie gras est un met traditionnel de Noël.'' Kontrowersyjny ze względów etycznych.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('les escargots (m. pl.)', 'Ślimaki — klasyczne danie francuskie, zwykle podawane z masłem czosnkowym i natką pietruszki (beurre persillé). Np. ''Une douzaine d''escargots de Bourgogne, s''il vous plaît.'' (12 ślimaków burgundzkich).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la pâtisserie', 'Cukiernia / ciastkarstwo. Słynne francuskie desery: macaron, éclair, mille-feuille, Paris-Brest, tarte tatin, opéra. le/la pâtissier(-ière) = cukiernik/cukierniczka.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('un macaron', 'Macaron — delikatne, okrągłe ciasteczko z migdałów z kremowym nadzieniem. Nie mylić z macarON (francuski) i macarOOn (kokosowe). Najsłynniejsze: Ladurée, Pierre Hermé. Różne smaki i kolory.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la charcuterie', 'Wędliny / delikatesy mięsne. Np. jambon (szynka), saucisson (kiełbasa sucha), pâté, rillettes, terrine. ''Une planche de charcuterie'' = deska wędlin (popularna na apéro).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('faire les courses / faire du shopping', '''Faire les courses'' = robić codzienne zakupy (jedzenie). ''Faire du shopping'' = iść na zakupy (ubrania, przyjemność). Np. ''Je fais les courses au supermarché.'' ''On fait du shopping samedi?''', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le terroir', 'Terroir — pojęcie bez dokładnego polskiego odpowiednika: unikalne cechy regionu (gleba, klimat, tradycje) nadające produktom charakter. Kluczowe dla wina i sera. Np. ''Ce vin exprime bien son terroir.''', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('AOC / AOP (Appellation d''Origine)', 'Chronione Oznaczenie Pochodzenia — certyfikat gwarantujący, że produkt pochodzi z konkretnego regionu i spełnia normy. Np. Champagne (tylko z regionu Szampanii), Roquefort, Camembert de Normandie.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vouvoyer vs Tutoyer', '''Vouvoyer'' = mówić ''vous'' (Pan/Pani — formalnie). ''Tutoyer'' = mówić ''tu'' (ty — nieformalnie). Np. ''On peut se tutoyer?'' (Czy możemy mówić sobie ''ty''?). W pracy, z nieznajomymi — ''vous''. Z rodziną, przyjaciółmi — ''tu''.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('le 14 juillet', '14 lipca — Święto Narodowe Francji (Dzień Bastylii). Upamiętnia szturm na Bastylię w 1789 roku. Obchody: defilada wojskowa na Polach Elizejskich, fajerwerki, bale strażackie (bals des pompiers).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('la Chandeleur', 'Święto Matki Boskiej Gromnicznej (2 lutego) — tradycja jedzenia naleśników (crêpes). Przesąd: trzymać monetę w lewej ręce i przewracać naleśnik prawą — przynosi szczęście i dobrobyt na cały rok.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
